<script setup lang="ts">import { watch } from 'vue'; import { dashboard } from '../api'; import { useFiltersStore } from '../stores/filters'; import { useAsyncData } from '../composables/useAsyncData'; import { useAutoRefresh } from '../composables/useAutoRefresh'; import AppShell from '../components/AppShell.vue'; import AsyncPanel from '../components/AsyncPanel.vue'; import StatusTag from '../components/StatusTag.vue'; const filters=useFiltersStore(); const state=useAsyncData(async()=>{const p={instance_id:filters.instance_id||undefined,limit:100}; const [agents,metrics,health,docker]=await Promise.all([dashboard.agents(p),dashboard.serverMetrics(p),dashboard.healthChecks(p),dashboard.dockerStatuses(p)]); return {agents:agents.items,metrics:metrics.items,health:health.items,docker:docker.items}}); watch(()=>filters.instance_id,()=>void state.reload()); useAutoRefresh(state.reload); const bytes=(n:number)=>`${(n/1024).toFixed(1)} KB/s`;</script>
<template><AppShell title="系统状态"><AsyncPanel :loading="state.loading.value" :error="state.error.value" @retry="state.reload"><div v-if="state.data.value" class="runtime-grid"><section class="panel"><h2>Agent</h2><el-table :data="state.data.value.agents"><el-table-column prop="id" label="Agent"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.online?'online':'offline'"/></template></el-table-column><el-table-column prop="last_log_id" label="游标"/><el-table-column prop="source_latest_log_id" label="源库最新"/><el-table-column label="积压"><template #default="s"><el-tag :type="s.row.backlog_estimate>3000?'danger':'success'">{{s.row.backlog_estimate}}</el-tag></template></el-table-column><el-table-column prop="report_delay_ms" label="上报延迟 ms"/></el-table></section><section class="panel"><h2>系统指标</h2><el-table :data="state.data.value.metrics"><el-table-column prop="instance_id" label="实例"/><el-table-column prop="cpu_percent" label="CPU %"/><el-table-column prop="memory_used_percent" label="内存 %"/><el-table-column prop="disk_used_percent" label="磁盘 %"/><el-table-column label="网络 RX"><template #default="s">{{bytes(s.row.network_rx_bytes_per_second)}}</template></el-table-column><el-table-column label="网络 TX"><template #default="s">{{bytes(s.row.network_tx_bytes_per_second)}}</template></el-table-column></el-table></section><section class="panel"><h2>健康检查</h2><el-table :data="state.data.value.health"><el-table-column prop="target" label="目标"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.status"/></template></el-table-column><el-table-column prop="http_status_code" label="HTTP"/><el-table-column prop="latency_ms" label="延迟 ms"/></el-table></section><section class="panel"><h2>容器</h2><el-table :data="state.data.value.docker"><el-table-column prop="container_name" label="容器"/><el-table-column label="状态"><template #default="s"><StatusTag :value="s.row.running?'running':'stopped'"/></template></el-table-column><el-table-column prop="status" label="详情"/></el-table></section></div></AsyncPanel></AppShell></template>
